--converts text with wikilinks to plain text, e.g "[[foo|gah]] is [[bar]]" to "gah is bar" --removes anything enclosed in tags and files, and italic and bold markup local p = {}
function p.main(frame) local text = frame.args[1] text = mw.ustring.gsub (text, '<.->.-<.->', '') --strip out flags, plus any other tags, e.g footnotes text = mw.ustring.gsub (text, '%[%[File:.-%]%]', '') --strip out files text = mw.ustring.gsub (text, '%[%[.-|', '') --strip out piped link text text = mw.ustring.gsub (text, '%[', '') --then strip out remaining [ and ] text = mw.ustring.gsub (text, '%]', '') text = txt:gsub("'''''", ""):gsub("''''", ""):gsub("'''", ""):gsub("''", "") return text end
return p

