--converts text with wikilinks to plain text, e.g "[[foo|gah]] is [[bar]]" to "gah is bar" --removes anything enclosed in tags and files, and italic and bold markup local p = {}
function p.main(frame) local text = frame.args[1] text = mw.ustring.gsub (text, '<.->.-<.->', '') --strip out flags, plus any other tags, e.g footnotes text = mw.ustring.gsub (text, '%[%[File:.-%]%]', '') --strip out files text = mw.ustring.gsub (text, '%[%[.-|', '') --strip out piped link text text = mw.ustring.gsub (text, '%[', '') --then strip out remaining [ and ] text = mw.ustring.gsub (text, '%]', '') text = mw.ustring.gsub (text, "'''''", "") --strip out italic and bold markup text = mw.ustring.gsub (text, "'''?", "") --not stripping out '''' gives correct output for bolded text in quotes return text end
return p

--converts text with wikilinks to plain text, e.g "[[foo|gah]] is [[bar]]" to "gah is bar" --removes anything enclosed in tags that mediawiki doesn't convert to strip markers (fails with nested tags too) and files, and italic and bold markup local p = {}
function p.main(frame) local text = frame.args[1] text = mw.ustring.gsub (text, '<.->.-<.->', '') --strip out tags text = mw.ustring.gsub (text, '%[%[File:.-%]%]', '') --strip out files text = mw.ustring.gsub (text, '%[%[.-|', '') --strip out piped link text text = mw.ustring.gsub (text, '%[', '') --then strip out remaining [ and ] text = mw.ustring.gsub (text, '%]', '') text = mw.ustring.gsub (text, "'''''", "") --strip out italic and bold markup text = mw.ustring.gsub (text, "'''?", "") --not stripping out '''' gives correct output for bolded text in quotes return text end
return p

--converts text with wikilinks to plain text, e.g "[[foo|gah]] is [[bar]]" to "gah is bar" --removes anything enclosed in tags that isn't nested, mediawiki strip markers (references etc), files, italic and bold markup local p = {}
function p.main(frame) local text = frame.args[1] text = mw.text.killMarkers (text) text = mw.ustring.gsub (text, '<.->.-<.->', '') --strip out tags text = mw.ustring.gsub (text, '%[%[File:.-%]%]', '') --strip out files text = mw.ustring.gsub (text, '%[%[.-|', '') --strip out piped link text text = mw.ustring.gsub (text, '%[', '') --then strip out remaining [ and ] text = mw.ustring.gsub (text, '%]', '') text = mw.ustring.gsub (text, "'''''", "") --strip out italic and bold markup text = mw.ustring.gsub (text, "'''?", "") --not stripping out '''' gives correct output for bolded text in quotes return text end
return p

--converts text with wikilinks to plain text, e.g "[[foo|gah]] is [[bar]]" to "gah is bar" --removes anything enclosed in tags that isn't nested, mediawiki strip markers (references etc), files, italic and bold markup local p = {}
function p.main(frame) local text = frame.args[1] or '' text = mw.text.killMarkers(text) :gsub('<.->.-<.->', '') --strip out tags :gsub('%[%[%s*File%s*:.-%]%]', '') --strip out files :gsub('%[%[.-|', '') --strip out piped link text :gsub('[%[%]]', '') --then strip out remaining [ and ] :gsub("'''''", "") --strip out bold italic markup :gsub("'''?", "") --not stripping out '''' gives correct output for bolded text in quotes return text end
return p
